import { cn } from '@/utils/cn';
import { cva, VariantProps } from 'class-variance-authority';
import { Component, createEffect, createUniqueId, mergeProps } from 'solid-js';

type CheckboxProps = {
  id?: string;
  name?: string;
  defaultChecked: boolean;
  indeterminate?: boolean;
  class?: string;
  size?: CheckboxVariantsProps['size'];
  color?: CheckboxVariantsProps['color'];
  disabled?: boolean;
  onChange?: (checked: boolean | null) => void;
  value?: string;
};

const variants = cva('checkbox', {
  variants: {
    size: {
      xs: 'checkbox-xs',
      sm: 'checkbox-sm',
      md: 'checkbox-md',
      lg: 'checkbox-lg',
      xl: 'checkbox-xl',
    },
    color: {
      default: '',
      neutral: 'checkbox-neutral',
      primary: 'checkbox-primary',
      secondary: 'checkbox-secondary',
      accent: 'checkbox-accent',
      info: 'checkbox-info',
      success: 'checkbox-success',
      warning: 'checkbox-warning',
      error: 'checkbox-error',
    },
  },
});

export type CheckboxVariantsProps = VariantProps<typeof variants>;

export const Checkbox: Component<CheckboxProps> = p => {
  p = mergeProps(
    { size: 'xs', color: 'primary', id: createUniqueId(), defaultChecked: false } as CheckboxProps,
    p,
  );

  return (
    <input
      ref={ref => {
        if (!ref) return;
        ref.checked = p.defaultChecked;
        p.indeterminate && (ref.value = 'inteterminate');
      }}
      type="checkbox"
      id={p.id}
      class={cn(variants({ size: p.size, color: p.color }), p.class)}
      disabled={p.disabled}
      {...(p.name && { name: p.name })}
      {...(p.indeterminate && { 'data-indeterminate': true })}
      onClick={e => {
        if (p.indeterminate || p.disabled) e.preventDefault();
      }}
      onChange={e => p.onChange && p.onChange(e.target.checked)}
      value={p.indeterminate ? 'inteterminate' : p.value}
    />
  );
};
